"""
自动生成：将 templates/*.html 内容内嵌为字典，供 DictLoader 从内存加载
(EdgeOne 云函数构建器不打包 templates/ 这类非 .py 静态资源)
"""
TEMPLATES = {
  "about.html": "{% extends \"base.html\" %}\n{% block title %}关于 · 北极星·炼术师{% endblock %}\n{% block content %}\n<div class=\"module-header\">\n    <div class=\"container\">\n        <h2>关于 AI 销售助理</h2>\n        <p class=\"mb-0 opacity-75\">北极星·炼术师 · 腾讯 AI 黑客松 · 方向三【营销】</p>\n    </div>\n</div>\n<div class=\"container\">\n    <div class=\"row g-4\">\n        <div class=\"col-lg-8\">\n            <div class=\"card\">\n                <div class=\"card-body\">\n                    <h4>🎯 我们解决什么问题</h4>\n                    <p>销售人员 80% 的时间被非成交动作吞噬 —— 查客户资料、憋话术、想跟进策略、写复盘。AI 销售助理把这些\"重复劳动\"压缩到分钟级，让销售专注于真正推动决策的关系与沟通。</p>\n\n                    <h4 class=\"mt-4\">🧭 五大模块，一站式贯穿销售全流程</h4>\n                    <div class=\"row g-3 mt-2\">\n                        <div class=\"col-md-6\"><div class=\"border rounded p-3\"><strong>1. 客户背景速查</strong><br><small class=\"text-muted\">融资、决策链、痛点，AI + 私有素材库双引擎</small></div></div>\n                        <div class=\"col-md-6\"><div class=\"border rounded p-3\"><strong>2. 触达内容生成</strong><br><small class=\"text-muted\">4 渠道、4 语气，一键出稿</small></div></div>\n                        <div class=\"col-md-6\"><div class=\"border rounded p-3\"><strong>3. 异议处理教练</strong><br><small class=\"text-muted\">4 步框架 + 逐字话术</small></div></div>\n                        <div class=\"col-md-6\"><div class=\"border rounded p-3\"><strong>4. 跟进节奏管理</strong><br><small class=\"text-muted\">阶段化建议 + 客户库联动</small></div></div>\n                        <div class=\"col-md-6\"><div class=\"border rounded p-3\"><strong>5. 销售过程复盘</strong><br><small class=\"text-muted\">对话拆解，识别错失机会</small></div></div>\n                        <div class=\"col-md-6\"><div class=\"border rounded p-3\"><strong>+ 私有素材库</strong><br><small class=\"text-muted\">BM25 检索，AI 调研时自动引用</small></div></div>\n                    </div>\n\n                    <h4 class=\"mt-4\">🛠️ 技术架构</h4>\n                    <ul>\n                        <li><strong>后端</strong>：Python 3.11 + Flask + SQLite</li>\n                        <li><strong>AI</strong>：OpenAI GPT-4o（可切换 Mock 模式）</li>\n                        <li><strong>检索</strong>：纯 Python BM25 实现（含中英文分词）</li>\n                        <li><strong>文档解析</strong>：pdftotext / python-docx</li>\n                        <li><strong>前端</strong>：Bootstrap 5 + 原生 JS</li>\n                        <li><strong>部署</strong>：WorkBuddy 沙箱 + 工蜂 CI/CD</li>\n                    </ul>\n\n                    <h4 class=\"mt-4\">💡 差异化亮点</h4>\n                    <ol>\n                        <li><strong>私有知识增强</strong>：AI 调研时会自动检索你上传的销售话术、案例、竞品分析，输出结果比通用 AI 更贴合业务</li>\n                        <li><strong>阶段感知</strong>：跟进/复盘模块基于客户所处阶段给出差异化建议，不是\"一套话术打天下\"</li>\n                        <li><strong>可平滑降级</strong>：真实 AI 不可用时自动切 Mock，保证 Demo 稳定</li>\n                        <li><strong>行动可闭环</strong>：从客户库 → 跟进 → 复盘 → 更新阶段，形成销售动作闭环</li>\n                    </ol>\n                </div>\n            </div>\n        </div>\n        <div class=\"col-lg-4\">\n            <div class=\"card mb-3\">\n                <div class=\"card-body text-center\">\n                    <div style=\"font-size:5rem; color:#00e5ff; text-shadow:0 0 30px rgba(0,229,255,.5);\">✦</div>\n                    <h4 class=\"mb-1\">北极星 · 炼术师</h4>\n                    <p class=\"text-muted mb-2\">Polaris Alchemists</p>\n                    <p class=\"small\">🌟 AI 炼真金 · 专业落地</p>\n                </div>\n            </div>\n            <div class=\"card\">\n                <div class=\"card-header\">📦 相关资源</div>\n                <div class=\"card-body\">\n                    <p class=\"small mb-2\">📌 <strong>代码仓库</strong></p>\n                    <a href=\"https://git.woa.com/csc/ai-sales-assistant\" target=\"_blank\" class=\"small\">git.woa.com/csc/ai-sales-assistant</a>\n                    <p class=\"small mb-2 mt-3\">📌 <strong>姊妹作品</strong></p>\n                    <a href=\"https://git.woa.com/csc/ai-content-creator\" target=\"_blank\" class=\"small\">AI 内容创作系统（方向二）</a>\n                </div>\n            </div>\n        </div>\n    </div>\n</div>\n{% endblock %}\n",
  "base.html": "<!DOCTYPE html>\n<html lang=\"zh-CN\">\n<head>\n    <meta charset=\"UTF-8\">\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n    <title>{% block title %}AI 销售助理 | 北极星·炼术师{% endblock %}</title>\n    <link href=\"https://cdn.jsdelivr.net/npm/bootstrap@5.3.0/dist/css/bootstrap.min.css\" rel=\"stylesheet\">\n    <link href=\"https://cdn.jsdelivr.net/npm/bootstrap-icons@1.11.1/font/bootstrap-icons.css\" rel=\"stylesheet\">\n    <style>\n        :root {\n            --primary: #0a1f44;\n            --primary-2: #1e40af;\n            --accent: #00e5ff;\n            --gold: #ffc857;\n            --light-bg: #f5f7fb;\n        }\n        body {\n            font-family: -apple-system, \"PingFang SC\", \"Microsoft YaHei\", sans-serif;\n            background: var(--light-bg);\n            color: #1a1a2e;\n        }\n        .navbar {\n            background: linear-gradient(135deg, var(--primary), var(--primary-2)) !important;\n            box-shadow: 0 2px 10px rgba(10,31,68,0.3);\n        }\n        .navbar-brand, .navbar .nav-link {\n            color: #fff !important;\n        }\n        .navbar-brand {\n            font-weight: 700;\n            font-size: 1.25rem;\n        }\n        .navbar-brand .brand-star {\n            color: var(--accent);\n            margin-right: 6px;\n        }\n        .nav-link {\n            transition: color .2s;\n            padding: .5rem .85rem !important;\n            font-size: .95rem;\n        }\n        .nav-link:hover, .nav-link.active {\n            color: var(--accent) !important;\n        }\n        .llm-badge {\n            font-size: .72rem;\n            padding: 2px 8px;\n            border-radius: 10px;\n            margin-left: 8px;\n            vertical-align: middle;\n        }\n        .llm-badge.real { background: #10b981; color: #fff; }\n        .llm-badge.mock { background: #f59e0b; color: #fff; }\n\n        .hero-section {\n            background: linear-gradient(135deg, var(--primary) 0%, var(--primary-2) 60%, #4c1d95 100%);\n            color: white;\n            padding: 90px 0 100px;\n            position: relative;\n            overflow: hidden;\n        }\n        .hero-section::before {\n            content: '';\n            position: absolute;\n            inset: 0;\n            background:\n                radial-gradient(circle at 20% 30%, rgba(0,229,255,.15), transparent 40%),\n                radial-gradient(circle at 80% 70%, rgba(255,200,87,.1), transparent 40%);\n            pointer-events: none;\n        }\n        .feature-card {\n            border: none;\n            border-radius: 14px;\n            transition: transform .3s, box-shadow .3s;\n            height: 100%;\n            background: #fff;\n        }\n        .feature-card:hover {\n            transform: translateY(-4px);\n            box-shadow: 0 12px 30px rgba(30,64,175,.15);\n        }\n        .feature-icon {\n            font-size: 2.4rem;\n            color: var(--primary-2);\n            margin-bottom: 12px;\n        }\n        .btn-primary {\n            background: var(--primary-2);\n            border-color: var(--primary-2);\n        }\n        .btn-primary:hover, .btn-primary:focus {\n            background: var(--primary);\n            border-color: var(--primary);\n        }\n        .btn-accent {\n            background: var(--accent);\n            color: var(--primary);\n            border: none;\n            font-weight: 600;\n        }\n        .btn-accent:hover { background: #00b8cc; color: #fff; }\n\n        .module-header {\n            background: linear-gradient(135deg, var(--primary), var(--primary-2));\n            color: white;\n            padding: 50px 0 40px;\n            margin-bottom: 30px;\n        }\n        .result-card {\n            border-left: 4px solid var(--primary-2);\n            background: #fff;\n            border-radius: 8px;\n        }\n        .tips-box {\n            background: #fff8e1;\n            border-left: 4px solid var(--gold);\n            padding: 14px 16px;\n            border-radius: 6px;\n        }\n        .source-tag {\n            display: inline-block;\n            font-size: .75rem;\n            padding: 2px 8px;\n            border-radius: 10px;\n            margin-left: 8px;\n        }\n        .source-tag.real { background: #d1fae5; color: #065f46; }\n        .source-tag.mock { background: #fef3c7; color: #92400e; }\n\n        footer {\n            background: var(--primary);\n            color: rgba(255,255,255,.85);\n            padding: 30px 0 20px;\n            margin-top: 60px;\n        }\n        footer a { color: var(--accent); text-decoration: none; }\n\n        .loading-spinner {\n            display: inline-block;\n            width: 1.2rem;\n            height: 1.2rem;\n            border: 2px solid rgba(255,255,255,.3);\n            border-top-color: #fff;\n            border-radius: 50%;\n            animation: spin .8s linear infinite;\n        }\n        @keyframes spin { to { transform: rotate(360deg); } }\n    </style>\n    {% block extra_css %}{% endblock %}\n</head>\n<body>\n    <nav class=\"navbar navbar-expand-lg\">\n        <div class=\"container\">\n            <a class=\"navbar-brand\" href=\"/\">\n                <span class=\"brand-star\">✦</span> AI 销售助理\n                <span class=\"llm-badge\" id=\"llm-badge\">…</span>\n            </a>\n            <button class=\"navbar-toggler\" type=\"button\" data-bs-toggle=\"collapse\" data-bs-target=\"#navbarNav\">\n                <span class=\"navbar-toggler-icon\"></span>\n            </button>\n            <div class=\"collapse navbar-collapse\" id=\"navbarNav\">\n                <ul class=\"navbar-nav ms-auto\">\n                    <li class=\"nav-item\"><a class=\"nav-link\" href=\"/\">首页</a></li>\n                    <li class=\"nav-item\"><a class=\"nav-link\" href=\"/customer-research\"><i class=\"bi bi-search\"></i> 客户速查</a></li>\n                    <li class=\"nav-item\"><a class=\"nav-link\" href=\"/outreach\"><i class=\"bi bi-send\"></i> 触达生成</a></li>\n                    <li class=\"nav-item\"><a class=\"nav-link\" href=\"/objection\"><i class=\"bi bi-shield-check\"></i> 异议处理</a></li>\n                    <li class=\"nav-item\"><a class=\"nav-link\" href=\"/followup\"><i class=\"bi bi-calendar-check\"></i> 跟进管理</a></li>\n                    <li class=\"nav-item\"><a class=\"nav-link\" href=\"/review\"><i class=\"bi bi-clipboard-data\"></i> 销售复盘</a></li>\n                    <li class=\"nav-item\"><a class=\"nav-link\" href=\"/library\"><i class=\"bi bi-folder\"></i> 素材库</a></li>\n                    <li class=\"nav-item\"><a class=\"nav-link\" href=\"/customers\"><i class=\"bi bi-people\"></i> 客户库</a></li>\n                    <li class=\"nav-item\"><a class=\"nav-link\" href=\"/about\"><i class=\"bi bi-info-circle\"></i> 关于</a></li>\n                </ul>\n            </div>\n        </div>\n    </nav>\n\n    <main>\n        {% block content %}{% endblock %}\n    </main>\n\n    <footer>\n        <div class=\"container\">\n            <div class=\"row\">\n                <div class=\"col-md-6\">\n                    <h5>✦ 北极星 · 炼术师</h5>\n                    <p class=\"mb-1\">AI 销售助理 - WorkBuddy 专业领域生产系统</p>\n                    <small>方向三【营销】· 腾讯 AI 黑客松参赛作品</small>\n                </div>\n                <div class=\"col-md-6 text-md-end\">\n                    <p class=\"mb-1\">🌟 AI 炼真金 · 专业落地</p>\n                    <small>© 2024 Polaris Alchemists</small>\n                </div>\n            </div>\n        </div>\n    </footer>\n\n    <script src=\"https://cdn.jsdelivr.net/npm/bootstrap@5.3.0/dist/js/bootstrap.bundle.min.js\"></script>\n    <script>\n        // 全局兜底：把 AI 返回的任意类型（字符串/数字/数组/对象）安全转成可读文本，\n        // 避免 AI 偏离约定的字段类型时前端出现 [object Object] 乱码。\n        function safeText(v, sep) {\n            sep = sep || '；';\n            if (v === null || v === undefined) return '';\n            if (typeof v === 'string') return v;\n            if (typeof v === 'number' || typeof v === 'boolean') return String(v);\n            if (Array.isArray(v)) return v.map(x => safeText(x, sep)).filter(Boolean).join(sep);\n            if (typeof v === 'object') return Object.values(v).map(x => safeText(x, sep)).filter(Boolean).join(' ');\n            return String(v);\n        }\n        // 专用于\"分步骤\"类字段（如切入策略）：数组会编号展示，字符串原样返回\n        function safeSteps(v) {\n            if (Array.isArray(v)) return v.map((item, i) => `${i + 1}. ${safeText(item)}`).join('\\n');\n            return safeText(v);\n        }\n\n        // 全局：拉取 LLM 状态\n        fetch('/api/system/info').then(r => r.json()).then(d => {\n            const b = document.getElementById('llm-badge');\n            if (!b) return;\n            if (d.llm_mode === 'real') {\n                b.className = 'llm-badge real';\n                b.textContent = 'AI · ' + (d.model || 'gpt-4o');\n            } else {\n                b.className = 'llm-badge mock';\n                b.textContent = 'Mock 演示';\n            }\n        }).catch(() => {});\n\n        // 高亮当前导航\n        const path = location.pathname;\n        document.querySelectorAll('.navbar-nav .nav-link').forEach(a => {\n            if (a.getAttribute('href') === path) a.classList.add('active');\n        });\n    </script>\n    {% block extra_js %}{% endblock %}\n</body>\n</html>\n",
  "customer_research.html": "{% extends \"base.html\" %}\n{% block title %}客户背景速查{% endblock %}\n{% block content %}\n<div class=\"module-header\">\n    <div class=\"container\">\n        <h2><i class=\"bi bi-search\"></i> 客户背景速查</h2>\n        <p class=\"mb-0 opacity-75\">输入公司名，3 分钟拿到全景画像 · AI 会自动检索你的私有素材库</p>\n    </div>\n</div>\n<div class=\"container\">\n    <div class=\"row g-4\">\n        <div class=\"col-lg-5\">\n            <div class=\"card\">\n                <div class=\"card-body\">\n                    <h5 class=\"card-title\">🎯 输入调研需求</h5>\n                    <div class=\"mb-3\">\n                        <label class=\"form-label\">公司名称 *</label>\n                        <input type=\"text\" class=\"form-control\" id=\"company\" placeholder=\"如：某某科技有限公司\">\n                    </div>\n                    <div class=\"mb-3\">\n                        <label class=\"form-label\">补充信息（可选）</label>\n                        <textarea class=\"form-control\" id=\"context\" rows=\"4\" placeholder=\"行业、规模、你已知的信息、想重点了解的方向...\"></textarea>\n                    </div>\n                    <button class=\"btn btn-primary w-100\" id=\"btn-go\"><i class=\"bi bi-lightning-charge\"></i> 开始调研</button>\n\n                    <div class=\"tips-box mt-3 small\">\n                        <strong>💡 使用提示</strong>\n                        <ul class=\"mb-0 mt-1 ps-3\">\n                            <li>公司名越具体越好（含\"股份\"、\"有限\"等后缀）</li>\n                            <li>补充\"我想切入哪个部门\"，AI 会针对性给切入策略</li>\n                            <li>提前在素材库上传相关行业案例，命中率更高</li>\n                        </ul>\n                    </div>\n                </div>\n            </div>\n        </div>\n        <div class=\"col-lg-7\">\n            <div id=\"result-panel\" class=\"d-none\">\n                <div class=\"card result-card mb-3\">\n                    <div class=\"card-body\">\n                        <h5 class=\"mb-3\">\n                            <i class=\"bi bi-file-earmark-text\"></i> <span id=\"r-name\"></span>\n                            <span class=\"source-tag\" id=\"r-source\"></span>\n                        </h5>\n                        <p class=\"text-muted\" id=\"r-basic\"></p>\n\n                        <hr>\n                        <h6>📰 近期动态</h6>\n                        <ul id=\"r-news\"></ul>\n\n                        <h6 class=\"mt-3\">👥 关键联系人</h6>\n                        <div id=\"r-contacts\" class=\"d-flex flex-wrap gap-2\"></div>\n\n                        <h6 class=\"mt-3\">🔗 决策链路</h6>\n                        <p id=\"r-chain\" class=\"mb-3 badge bg-light text-dark p-2\"></p>\n\n                        <h6>😩 潜在痛点</h6>\n                        <ul id=\"r-pains\"></ul>\n\n                        <h6 class=\"mt-3\">🚀 切入策略</h6>\n                        <div class=\"alert alert-info mb-0\" id=\"r-reco\" style=\"white-space:pre-wrap;\"></div>\n                    </div>\n                </div>\n\n                <div class=\"card\" id=\"kb-panel\">\n                    <div class=\"card-header\"><i class=\"bi bi-folder\"></i> 命中的私有素材</div>\n                    <div class=\"card-body\" id=\"kb-hits\"></div>\n                </div>\n            </div>\n            <div id=\"empty\" class=\"text-center text-muted py-5\">\n                <div style=\"font-size:4rem;\">🔍</div>\n                <p>输入公司名后，点击左侧按钮开始</p>\n            </div>\n        </div>\n    </div>\n</div>\n\n<script>\ndocument.getElementById('btn-go').onclick = async () => {\n    const company = document.getElementById('company').value.trim();\n    if (!company) { alert('请填公司名'); return; }\n    const context = document.getElementById('context').value.trim();\n    const btn = document.getElementById('btn-go');\n    btn.disabled = true;\n    btn.innerHTML = '<span class=\"loading-spinner\"></span> AI 正在调研…';\n\n    try {\n        const r = await fetch('/api/customer-research', {\n            method: 'POST', headers: {'Content-Type': 'application/json'},\n            body: JSON.stringify({company, context}),\n        }).then(r => r.json());\n\n        document.getElementById('empty').classList.add('d-none');\n        document.getElementById('result-panel').classList.remove('d-none');\n\n        const d = r.data || {};\n        document.getElementById('r-name').textContent = d.company_name || company;\n        const tag = document.getElementById('r-source');\n        tag.className = 'source-tag ' + r.source;\n        tag.textContent = r.source === 'real' ? '真实 AI' : 'Mock';\n\n        document.getElementById('r-basic').textContent = safeText(d.basic_info) || '（AI 未返回基础信息）';\n        document.getElementById('r-news').innerHTML = (d.recent_news || []).map(n => `<li>${safeText(n)}</li>`).join('') || '<li class=\"text-muted\">-</li>';\n        document.getElementById('r-contacts').innerHTML = (d.key_contacts || []).map(c => {\n            if (typeof c === 'string') return `<span class=\"badge bg-primary p-2\">${c}</span>`;\n            return `<span class=\"badge bg-primary p-2\">${safeText(c.name) || ''} · ${safeText(c.position) || ''}</span>`;\n        }).join('') || '<span class=\"text-muted\">-</span>';\n        document.getElementById('r-chain').textContent = safeText(d.decision_chain) || '-';\n        document.getElementById('r-pains').innerHTML = (d.pain_points || []).map(p => `<li>${safeText(p)}</li>`).join('') || '<li class=\"text-muted\">-</li>';\n        document.getElementById('r-reco').textContent = safeSteps(d.recommendation) || '-';\n\n        const kb = document.getElementById('kb-hits');\n        if (r.kb_hits && r.kb_hits.length) {\n            kb.innerHTML = r.kb_hits.map(h => `<div class=\"border rounded p-2 mb-2\"><strong>${h.filename}</strong> <span class=\"badge bg-info\">${h.score}</span><div class=\"small text-muted mt-1\">${h.snippet.substring(0,200)}…</div></div>`).join('');\n        } else {\n            kb.innerHTML = '<small class=\"text-muted\">本次调研未命中私有素材（可以到<a href=\"/library\">素材库</a>上传相关资料）</small>';\n        }\n    } catch (e) { alert('调研失败：' + e); }\n    btn.disabled = false;\n    btn.innerHTML = '<i class=\"bi bi-lightning-charge\"></i> 开始调研';\n};\n</script>\n{% endblock %}\n",
  "customers.html": "{% extends \"base.html\" %}\n{% block title %}客户库 · AI 销售助理{% endblock %}\n{% block content %}\n<div class=\"module-header\">\n    <div class=\"container\">\n        <h2><i class=\"bi bi-people\"></i> 客户库</h2>\n        <p class=\"mb-0 opacity-75\">管理你的目标客户，AI 会根据阶段自动推荐跟进节奏</p>\n    </div>\n</div>\n<div class=\"container\">\n    <div class=\"row g-4\">\n        <div class=\"col-lg-4\">\n            <div class=\"card\">\n                <div class=\"card-header\"><i class=\"bi bi-plus-circle\"></i> 新增客户</div>\n                <div class=\"card-body\">\n                    <form id=\"c-form\">\n                        <div class=\"mb-2\"><input class=\"form-control\" placeholder=\"姓名 *\" id=\"c-name\" required></div>\n                        <div class=\"mb-2\"><input class=\"form-control\" placeholder=\"公司\" id=\"c-company\"></div>\n                        <div class=\"mb-2\"><input class=\"form-control\" placeholder=\"行业\" id=\"c-industry\"></div>\n                        <div class=\"mb-2\"><input class=\"form-control\" placeholder=\"联系方式\" id=\"c-contact\"></div>\n                        <div class=\"mb-2\">\n                            <select class=\"form-select\" id=\"c-stage\">\n                                <option>初次接触</option><option>需求确认</option>\n                                <option>方案报价</option><option>决策等待</option><option>已成交</option>\n                            </select>\n                        </div>\n                        <div class=\"mb-2\"><textarea class=\"form-control\" rows=\"2\" placeholder=\"备注\" id=\"c-notes\"></textarea></div>\n                        <button class=\"btn btn-primary w-100\" type=\"submit\"><i class=\"bi bi-check-lg\"></i> 添加</button>\n                    </form>\n                </div>\n            </div>\n        </div>\n        <div class=\"col-lg-8\">\n            <div class=\"card\">\n                <div class=\"card-header d-flex justify-content-between align-items-center\">\n                    <span><i class=\"bi bi-list-ul\"></i> 客户列表</span>\n                    <button class=\"btn btn-sm btn-outline-primary\" onclick=\"loadC()\"><i class=\"bi bi-arrow-clockwise\"></i></button>\n                </div>\n                <div class=\"card-body\"><div id=\"c-list\">加载中…</div></div>\n            </div>\n        </div>\n    </div>\n</div>\n\n<script>\nconst STAGES = ['初次接触','需求确认','方案报价','决策等待','已成交'];\nasync function loadC() {\n    const r = await fetch('/api/customers/list').then(r => r.json());\n    const box = document.getElementById('c-list');\n    if (!r.customers.length) {\n        box.innerHTML = '<p class=\"text-muted text-center py-4\">还没有客户，先添加一个吧</p>';\n        return;\n    }\n    box.innerHTML = '<table class=\"table table-hover\"><thead><tr><th>姓名</th><th>公司</th><th>行业</th><th>阶段</th><th></th></tr></thead><tbody>' +\n        r.customers.map(c => `\n            <tr>\n                <td><strong>${c.name}</strong><br><small class=\"text-muted\">${c.contact || ''}</small></td>\n                <td>${c.company || '-'}</td>\n                <td>${c.industry || '-'}</td>\n                <td>\n                    <select class=\"form-select form-select-sm\" onchange=\"upd(${c.id}, this.value)\">\n                        ${STAGES.map(s => `<option ${s === c.stage ? 'selected' : ''}>${s}</option>`).join('')}\n                    </select>\n                </td>\n                <td>\n                    <a class=\"btn btn-sm btn-outline-primary\" href=\"/followup?name=${encodeURIComponent(c.name)}&stage=${encodeURIComponent(c.stage)}\"><i class=\"bi bi-arrow-right\"></i> 跟进</a>\n                    <button class=\"btn btn-sm btn-outline-danger\" onclick=\"delC(${c.id})\"><i class=\"bi bi-trash\"></i></button>\n                </td>\n            </tr>`).join('') + '</tbody></table>';\n}\n\nasync function upd(id, stage) {\n    await fetch('/api/customers/update/' + id, {method: 'POST', headers: {'Content-Type': 'application/json'}, body: JSON.stringify({stage})});\n    loadC();\n}\nasync function delC(id) {\n    if (!confirm('删除？')) return;\n    await fetch('/api/customers/delete/' + id, {method: 'DELETE'});\n    loadC();\n}\n\ndocument.getElementById('c-form').onsubmit = async e => {\n    e.preventDefault();\n    const body = {\n        name: document.getElementById('c-name').value,\n        company: document.getElementById('c-company').value,\n        industry: document.getElementById('c-industry').value,\n        contact: document.getElementById('c-contact').value,\n        stage: document.getElementById('c-stage').value,\n        notes: document.getElementById('c-notes').value,\n    };\n    await fetch('/api/customers/add', {method: 'POST', headers: {'Content-Type': 'application/json'}, body: JSON.stringify(body)});\n    document.getElementById('c-form').reset();\n    loadC();\n};\nloadC();\n</script>\n{% endblock %}\n",
  "followup.html": "{% extends \"base.html\" %}\n{% block title %}跟进节奏管理{% endblock %}\n{% block content %}\n<div class=\"module-header\">\n    <div class=\"container\">\n        <h2><i class=\"bi bi-calendar-check\"></i> 跟进节奏管理</h2>\n        <p class=\"mb-0 opacity-75\">按客户阶段给出下一步动作、时机、渠道，还有一段可直接说出口的话术</p>\n    </div>\n</div>\n<div class=\"container\">\n    <div class=\"row g-4\">\n        <div class=\"col-lg-5\">\n            <div class=\"card\">\n                <div class=\"card-body\">\n                    <label class=\"form-label fw-bold\">客户当前阶段</label>\n                    <select class=\"form-select\" id=\"status\">\n                        <option>初次接触</option><option>需求确认</option>\n                        <option>方案报价</option><option>决策等待</option><option>已成交</option>\n                    </select>\n                    <label class=\"form-label fw-bold mt-3\">客户信息（可选）</label>\n                    <input class=\"form-control\" id=\"customer\" placeholder=\"如：张总 · 某某科技 CTO\">\n                    <label class=\"form-label fw-bold mt-3\">上次沟通记录（可选）</label>\n                    <textarea class=\"form-control\" id=\"last_talk\" rows=\"4\" placeholder=\"上次聊了什么、客户反馈、承诺...\"></textarea>\n                    <button class=\"btn btn-primary w-100 mt-3\" id=\"btn-go\"><i class=\"bi bi-arrow-right-circle\"></i> 生成跟进计划</button>\n                </div>\n            </div>\n        </div>\n        <div class=\"col-lg-7\">\n            <div id=\"result\" class=\"d-none\">\n                <div class=\"card result-card mb-3\">\n                    <div class=\"card-body\">\n                        <h5>📅 当前阶段：<span id=\"r-stage\" class=\"badge bg-primary\"></span> <span class=\"source-tag\" id=\"r-source\"></span></h5>\n\n                        <div class=\"row g-3 mt-2\">\n                            <div class=\"col-6\"><div class=\"border rounded p-3\"><small class=\"text-muted\">下一步动作</small><div class=\"fw-bold mt-1\" id=\"p-action\"></div></div></div>\n                            <div class=\"col-6\"><div class=\"border rounded p-3\"><small class=\"text-muted\">最佳时机</small><div class=\"fw-bold mt-1\" id=\"p-timing\"></div></div></div>\n                            <div class=\"col-6\"><div class=\"border rounded p-3\"><small class=\"text-muted\">推荐渠道</small><div class=\"fw-bold mt-1\" id=\"p-channel\"></div></div></div>\n                            <div class=\"col-6\"><div class=\"border rounded p-3\"><small class=\"text-muted\">阶段目标</small><div class=\"fw-bold mt-1\" id=\"p-goal\"></div></div></div>\n                        </div>\n\n                        <h6 class=\"mt-3\">💬 建议话术</h6>\n                        <div class=\"alert alert-primary mb-3\" id=\"p-script\" style=\"white-space:pre-wrap;\">-</div>\n\n                        <div class=\"alert alert-warning mb-0\" id=\"p-risk\"><strong>⚠️ 风险提示：</strong><span></span></div>\n                    </div>\n                </div>\n\n                <div class=\"card\">\n                    <div class=\"card-header\"><i class=\"bi bi-signpost-split\"></i> 客户旅程</div>\n                    <div class=\"card-body\">\n                        <div id=\"journey\" class=\"d-flex flex-wrap gap-2\"></div>\n                    </div>\n                </div>\n            </div>\n            <div id=\"empty\" class=\"text-center text-muted py-5\">\n                <div style=\"font-size:4rem;\">📅</div>\n                <p>选择客户阶段，AI 给你排好接下来的动作</p>\n            </div>\n        </div>\n    </div>\n</div>\n\n<script>\n// 从 URL 参数预填（客户库跳转来）\nconst params = new URLSearchParams(location.search);\nif (params.get('stage')) document.getElementById('status').value = params.get('stage');\nif (params.get('name')) document.getElementById('customer').value = params.get('name');\n\ndocument.getElementById('btn-go').onclick = async () => {\n    const body = {\n        status: document.getElementById('status').value,\n        customer: document.getElementById('customer').value,\n        last_talk: document.getElementById('last_talk').value,\n    };\n    const btn = document.getElementById('btn-go');\n    btn.disabled = true; btn.innerHTML = '<span class=\"loading-spinner\"></span> 生成中…';\n    try {\n        const r = await fetch('/api/followup', {method: 'POST', headers: {'Content-Type': 'application/json'}, body: JSON.stringify(body)}).then(r => r.json());\n        document.getElementById('empty').classList.add('d-none');\n        document.getElementById('result').classList.remove('d-none');\n        const d = r.data || {};\n        document.getElementById('r-stage').textContent = safeText(d.stage) || body.status;\n        const tag = document.getElementById('r-source');\n        tag.className = 'source-tag ' + r.source;\n        tag.textContent = r.source === 'real' ? '真实 AI' : 'Mock';\n        const p = d.plan || {};\n        document.getElementById('p-action').textContent = safeText(p.action) || '-';\n        document.getElementById('p-timing').textContent = safeText(p.timing) || '-';\n        document.getElementById('p-channel').textContent = safeText(p.channel) || '-';\n        document.getElementById('p-goal').textContent = safeText(p.goal) || '-';\n        document.getElementById('p-script').textContent = safeText(p.script) || '（本次未生成话术）';\n        document.querySelector('#p-risk span').textContent = safeText(d.risk) || '暂无';\n\n        const journey = d.journey || ['初次接触', '需求确认', '方案报价', '决策等待', '已成交'];\n        document.getElementById('journey').innerHTML = journey.map(s => {\n            const label = safeText(s);\n            return `<span class=\"badge ${label === safeText(d.stage) ? 'bg-primary' : 'bg-light text-dark'} p-2\">${label}</span>`;\n        }).join(' <i class=\"bi bi-arrow-right\"></i> ').replace(/> /g, '> ');\n    } catch (e) { alert('失败：' + e); }\n    btn.disabled = false; btn.innerHTML = '<i class=\"bi bi-arrow-right-circle\"></i> 生成跟进计划';\n};\n</script>\n{% endblock %}\n",
  "index.html": "{% extends \"base.html\" %}\n{% block title %}AI 销售助理 · 首页{% endblock %}\n{% block content %}\n<section class=\"hero-section\">\n    <div class=\"container position-relative\">\n        <div class=\"row align-items-center\">\n            <div class=\"col-lg-7\">\n                <h6 class=\"text-uppercase mb-2\" style=\"letter-spacing:2px; color:#00e5ff;\">Polaris Alchemists · 北极星·炼术师</h6>\n                <h1 class=\"display-4 fw-bold mb-3\">AI 销售助理</h1>\n                <p class=\"lead mb-4\">让每个销售都拥有一位 24 小时在线的 AI 军师<br>\n                    从客户调研、触达、异议处理到跟进复盘 - 一站式贯穿销售全流程</p>\n                <div class=\"d-flex gap-2 flex-wrap\">\n                    <a href=\"/customer-research\" class=\"btn btn-accent btn-lg\"><i class=\"bi bi-rocket-takeoff\"></i> 立即体验</a>\n                    <a href=\"/about\" class=\"btn btn-outline-light btn-lg\">了解方案</a>\n                </div>\n            </div>\n            <div class=\"col-lg-5 text-center d-none d-lg-block\">\n                <div style=\"font-size:12rem; line-height:1; text-shadow:0 0 40px rgba(0,229,255,.6);\">✦</div>\n            </div>\n        </div>\n    </div>\n</section>\n\n<div class=\"container py-5\">\n    <div class=\"text-center mb-5\">\n        <h2 class=\"fw-bold\">五大核心模块</h2>\n        <p class=\"text-muted\">覆盖销售全链路，让 AI 成为你的第二大脑</p>\n    </div>\n    <div class=\"row g-4\">\n        <div class=\"col-md-6 col-lg-4\">\n            <a href=\"/customer-research\" class=\"text-decoration-none text-dark\">\n                <div class=\"card feature-card p-4\">\n                    <div class=\"feature-icon\"><i class=\"bi bi-search\"></i></div>\n                    <h5>客户背景速查</h5>\n                    <p class=\"text-muted small\">3 分钟拿到客户全景画像：融资、决策链、痛点、切入策略</p>\n                </div>\n            </a>\n        </div>\n        <div class=\"col-md-6 col-lg-4\">\n            <a href=\"/outreach\" class=\"text-decoration-none text-dark\">\n                <div class=\"card feature-card p-4\">\n                    <div class=\"feature-icon\"><i class=\"bi bi-send\"></i></div>\n                    <h5>触达内容生成</h5>\n                    <p class=\"text-muted small\">微信/邮件/电话/LinkedIn 四种渠道，一键生成有回复率的开场白</p>\n                </div>\n            </a>\n        </div>\n        <div class=\"col-md-6 col-lg-4\">\n            <a href=\"/objection\" class=\"text-decoration-none text-dark\">\n                <div class=\"card feature-card p-4\">\n                    <div class=\"feature-icon\"><i class=\"bi bi-shield-check\"></i></div>\n                    <h5>异议处理教练</h5>\n                    <p class=\"text-muted small\">遇到\"太贵了/再考虑一下\"？AI 给你 4 步框架 + 逐字话术</p>\n                </div>\n            </a>\n        </div>\n        <div class=\"col-md-6 col-lg-4\">\n            <a href=\"/followup\" class=\"text-decoration-none text-dark\">\n                <div class=\"card feature-card p-4\">\n                    <div class=\"feature-icon\"><i class=\"bi bi-calendar-check\"></i></div>\n                    <h5>跟进节奏管理</h5>\n                    <p class=\"text-muted small\">按客户阶段给出下一步动作、时机、渠道，配套话术直接可用</p>\n                </div>\n            </a>\n        </div>\n        <div class=\"col-md-6 col-lg-4\">\n            <a href=\"/review\" class=\"text-decoration-none text-dark\">\n                <div class=\"card feature-card p-4\">\n                    <div class=\"feature-icon\"><i class=\"bi bi-clipboard-data\"></i></div>\n                    <h5>销售过程复盘</h5>\n                    <p class=\"text-muted small\">丢一段对话记录进去，AI 拆解意向度、错失点、改进项</p>\n                </div>\n            </a>\n        </div>\n        <div class=\"col-md-6 col-lg-4\">\n            <a href=\"/library\" class=\"text-decoration-none text-dark\">\n                <div class=\"card feature-card p-4\">\n                    <div class=\"feature-icon\"><i class=\"bi bi-folder\"></i></div>\n                    <h5>私有素材库</h5>\n                    <p class=\"text-muted small\">上传销售话术/案例/产品手册，AI 调研时自动检索复用</p>\n                </div>\n            </a>\n        </div>\n    </div>\n\n    <div class=\"mt-5 p-4 rounded\" style=\"background: linear-gradient(135deg, #f0f9ff, #ede9fe);\">\n        <div class=\"row align-items-center\">\n            <div class=\"col-md-8\">\n                <h5 class=\"mb-2\">🔥 为什么销售需要 AI 助理？</h5>\n                <p class=\"mb-0 text-muted\">销售 80% 的时间花在了非成交环节 —— 找资料、写话术、想跟进策略。AI 助理帮你把这些\"重复劳动\"压缩到分钟级，让你专注于建立关系和推进决策。</p>\n            </div>\n            <div class=\"col-md-4 text-md-end mt-3 mt-md-0\">\n                <a href=\"/customer-research\" class=\"btn btn-primary\">开始第一次调研 →</a>\n            </div>\n        </div>\n    </div>\n</div>\n{% endblock %}\n",
  "library.html": "{% extends \"base.html\" %}\n{% block title %}素材库 · AI 销售助理{% endblock %}\n{% block content %}\n<div class=\"module-header\">\n    <div class=\"container\">\n        <h2><i class=\"bi bi-folder\"></i> 私有素材库</h2>\n        <p class=\"mb-0 opacity-75\">上传销售话术、成功案例、产品手册、客户对话记录 —— AI 会在调研和复盘时自动检索</p>\n    </div>\n</div>\n<div class=\"container\">\n    <div class=\"row g-4\">\n        <!-- 上传区 -->\n        <div class=\"col-lg-5\">\n            <div class=\"card\">\n                <div class=\"card-header\"><i class=\"bi bi-cloud-upload\"></i> 上传素材</div>\n                <div class=\"card-body\">\n                    <form id=\"upload-form\">\n                        <div class=\"mb-3\">\n                            <label class=\"form-label\">选择文件</label>\n                            <input type=\"file\" class=\"form-control\" id=\"file\" required\n                                accept=\".txt,.md,.pdf,.docx,.doc,.csv,.json,.log\">\n                            <small class=\"text-muted\">支持 txt / md / pdf / docx / csv / json，最大 20 MB</small>\n                        </div>\n                        <div class=\"mb-3\">\n                            <label class=\"form-label\">分类</label>\n                            <select class=\"form-select\" id=\"category\">\n                                <option>通用</option>\n                                <option>销售话术</option>\n                                <option>成功案例</option>\n                                <option>产品手册</option>\n                                <option>客户对话</option>\n                                <option>竞品分析</option>\n                            </select>\n                        </div>\n                        <div class=\"mb-3\">\n                            <label class=\"form-label\">标签（可选，逗号分隔）</label>\n                            <input type=\"text\" class=\"form-control\" id=\"tags\" placeholder=\"如：SaaS,金融行业,决策者\">\n                        </div>\n                        <button type=\"submit\" class=\"btn btn-primary w-100\" id=\"btn-upload\">\n                            <i class=\"bi bi-upload\"></i> 上传\n                        </button>\n                    </form>\n                </div>\n            </div>\n\n            <div class=\"card mt-4\">\n                <div class=\"card-header\"><i class=\"bi bi-search\"></i> 检索测试</div>\n                <div class=\"card-body\">\n                    <div class=\"input-group\">\n                        <input type=\"text\" class=\"form-control\" id=\"q\" placeholder=\"输入关键词，如 金融 SaaS 报价\">\n                        <button class=\"btn btn-primary\" id=\"btn-search\"><i class=\"bi bi-search\"></i></button>\n                    </div>\n                    <div id=\"hits\" class=\"mt-3\"></div>\n                </div>\n            </div>\n        </div>\n        <!-- 列表区 -->\n        <div class=\"col-lg-7\">\n            <div class=\"card\">\n                <div class=\"card-header d-flex justify-content-between align-items-center\">\n                    <span><i class=\"bi bi-list-ul\"></i> 素材列表</span>\n                    <button class=\"btn btn-sm btn-outline-primary\" onclick=\"loadList()\"><i class=\"bi bi-arrow-clockwise\"></i> 刷新</button>\n                </div>\n                <div class=\"card-body\">\n                    <div id=\"doc-list\">加载中…</div>\n                </div>\n            </div>\n        </div>\n    </div>\n</div>\n\n<script>\nasync function loadList() {\n    const r = await fetch('/api/library/list').then(r => r.json());\n    const box = document.getElementById('doc-list');\n    if (!r.docs || !r.docs.length) {\n        box.innerHTML = '<p class=\"text-muted text-center py-4\">还没有素材，先上传几份试试 👈</p>';\n        return;\n    }\n    box.innerHTML = '<table class=\"table table-hover\"><thead><tr><th>文件名</th><th>分类</th><th>标签</th><th>大小</th><th></th></tr></thead><tbody>' +\n        r.docs.map(d => `\n            <tr>\n                <td><i class=\"bi bi-file-earmark-text\"></i> ${d.filename}</td>\n                <td><span class=\"badge bg-secondary\">${d.category}</span></td>\n                <td><small class=\"text-muted\">${d.tags || '-'}</small></td>\n                <td><small>${(d.size / 1024).toFixed(1)} KB</small></td>\n                <td><button class=\"btn btn-sm btn-outline-danger\" onclick=\"del(${d.id})\"><i class=\"bi bi-trash\"></i></button></td>\n            </tr>`).join('') + '</tbody></table>';\n}\n\nasync function del(id) {\n    if (!confirm('确认删除？')) return;\n    await fetch('/api/library/delete/' + id, {method: 'DELETE'});\n    loadList();\n}\n\ndocument.getElementById('upload-form').onsubmit = async e => {\n    e.preventDefault();\n    const f = document.getElementById('file').files[0];\n    if (!f) return;\n    const fd = new FormData();\n    fd.append('file', f);\n    fd.append('category', document.getElementById('category').value);\n    fd.append('tags', document.getElementById('tags').value);\n    const btn = document.getElementById('btn-upload');\n    btn.disabled = true; btn.innerHTML = '<span class=\"loading-spinner\"></span> 上传中…';\n    try {\n        const r = await fetch('/api/library/upload', {method: 'POST', body: fd}).then(r => r.json());\n        if (r.success) {\n            alert('上传成功');\n            document.getElementById('upload-form').reset();\n            loadList();\n        } else {\n            alert('失败：' + r.error);\n        }\n    } catch (e) { alert('失败：' + e); }\n    btn.disabled = false; btn.innerHTML = '<i class=\"bi bi-upload\"></i> 上传';\n};\n\ndocument.getElementById('btn-search').onclick = async () => {\n    const q = document.getElementById('q').value.trim();\n    if (!q) return;\n    const r = await fetch('/api/library/search?q=' + encodeURIComponent(q)).then(r => r.json());\n    const box = document.getElementById('hits');\n    if (!r.hits.length) { box.innerHTML = '<small class=\"text-muted\">无匹配结果</small>'; return; }\n    box.innerHTML = r.hits.map(h => `\n        <div class=\"border rounded p-2 mb-2 small\">\n            <div><strong>${h.filename}</strong> <span class=\"badge bg-info\">${h.score}</span></div>\n            <div class=\"text-muted mt-1\">${h.snippet.substring(0, 150)}…</div>\n        </div>`).join('');\n};\n\nloadList();\n</script>\n{% endblock %}\n",
  "objection.html": "{% extends \"base.html\" %}\n{% block title %}异议处理教练{% endblock %}\n{% block content %}\n<div class=\"module-header\">\n    <div class=\"container\">\n        <h2><i class=\"bi bi-shield-check\"></i> 异议处理教练</h2>\n        <p class=\"mb-0 opacity-75\">遇到\"太贵了\"、\"再考虑一下\"？AI 教你 4 步框架 + 逐字话术</p>\n    </div>\n</div>\n<div class=\"container\">\n    <div class=\"row g-4\">\n        <div class=\"col-lg-5\">\n            <div class=\"card\">\n                <div class=\"card-body\">\n                    <label class=\"form-label fw-bold\">客户说了什么？*</label>\n                    <textarea class=\"form-control\" id=\"objection\" rows=\"4\" placeholder=\"比如：你们价格太贵了 / 我再考虑一下 / 已经在用竞品了\"></textarea>\n                    <label class=\"form-label fw-bold mt-3\">背景补充（可选）</label>\n                    <textarea class=\"form-control\" id=\"context\" rows=\"3\" placeholder=\"如：客户是金融业 CIO，预算 50 万，已谈了两次\"></textarea>\n                    <button class=\"btn btn-primary w-100 mt-3\" id=\"btn-go\"><i class=\"bi bi-lightbulb\"></i> 生成应对策略</button>\n\n                    <div class=\"mt-3\">\n                        <div class=\"small text-muted mb-2\">常见异议速填：</div>\n                        <div class=\"d-flex flex-wrap gap-2\">\n                            <button class=\"btn btn-sm btn-outline-secondary\" onclick=\"fill(this)\">价格太贵了</button>\n                            <button class=\"btn btn-sm btn-outline-secondary\" onclick=\"fill(this)\">我再考虑一下</button>\n                            <button class=\"btn btn-sm btn-outline-secondary\" onclick=\"fill(this)\">已经在用竞品</button>\n                            <button class=\"btn btn-sm btn-outline-secondary\" onclick=\"fill(this)\">等预算下来再说</button>\n                            <button class=\"btn btn-sm btn-outline-secondary\" onclick=\"fill(this)\">需要老板同意</button>\n                        </div>\n                    </div>\n                </div>\n            </div>\n        </div>\n        <div class=\"col-lg-7\">\n            <div id=\"result\" class=\"d-none\">\n                <div class=\"card result-card\">\n                    <div class=\"card-body\">\n                        <h5>🎯 <span id=\"r-type\"></span> <span class=\"source-tag\" id=\"r-source\"></span></h5>\n                        <p><strong>核心策略：</strong><span id=\"r-strategy\"></span></p>\n\n                        <h6 class=\"mt-3\">📐 4 步应对框架</h6>\n                        <ol id=\"r-framework\"></ol>\n\n                        <h6 class=\"mt-3\">💬 建议话术</h6>\n                        <div class=\"alert alert-primary\" id=\"r-script\" style=\"white-space:pre-wrap;\"></div>\n\n                        <h6 class=\"mt-3\">📚 同行业案例</h6>\n                        <div class=\"alert alert-secondary mb-0\" id=\"r-cases\"></div>\n                    </div>\n                </div>\n            </div>\n            <div id=\"empty\" class=\"text-center text-muted py-5\">\n                <div style=\"font-size:4rem;\">🛡️</div>\n                <p>输入客户异议后，AI 会给出应对方案</p>\n            </div>\n        </div>\n    </div>\n</div>\n\n<script>\nfunction fill(btn) { document.getElementById('objection').value = btn.textContent; }\n\ndocument.getElementById('btn-go').onclick = async () => {\n    const objection = document.getElementById('objection').value.trim();\n    if (!objection) { alert('请输入客户异议'); return; }\n    const context = document.getElementById('context').value.trim();\n    const btn = document.getElementById('btn-go');\n    btn.disabled = true; btn.innerHTML = '<span class=\"loading-spinner\"></span> 生成中…';\n    try {\n        const r = await fetch('/api/objection', {method: 'POST', headers: {'Content-Type': 'application/json'}, body: JSON.stringify({objection, context})}).then(r => r.json());\n        document.getElementById('empty').classList.add('d-none');\n        document.getElementById('result').classList.remove('d-none');\n        const d = r.data || {};\n        document.getElementById('r-type').textContent = safeText(d.type) || '异议';\n        const tag = document.getElementById('r-source');\n        tag.className = 'source-tag ' + r.source;\n        tag.textContent = r.source === 'real' ? '真实 AI' : 'Mock';\n        document.getElementById('r-strategy').textContent = safeText(d.strategy) || '-';\n        document.getElementById('r-framework').innerHTML = (d.response_framework || []).map(x => `<li>${safeText(x)}</li>`).join('') || '<li class=\"text-muted\">-</li>';\n        document.getElementById('r-script').textContent = safeText(d.suggested_script) || r.raw;\n        document.getElementById('r-cases').textContent = safeText(d.similar_cases) || '-';\n    } catch (e) { alert('失败：' + e); }\n    btn.disabled = false; btn.innerHTML = '<i class=\"bi bi-lightbulb\"></i> 生成应对策略';\n};\n</script>\n{% endblock %}\n",
  "outreach.html": "{% extends \"base.html\" %}\n{% block title %}触达内容生成{% endblock %}\n{% block content %}\n<div class=\"module-header\">\n    <div class=\"container\">\n        <h2><i class=\"bi bi-send\"></i> 触达内容生成</h2>\n        <p class=\"mb-0 opacity-75\">四种渠道，一键生成有回复率的开场白</p>\n    </div>\n</div>\n<div class=\"container\">\n    <div class=\"row g-4\">\n        <div class=\"col-lg-5\">\n            <div class=\"card\">\n                <div class=\"card-body\">\n                    <div class=\"mb-3\">\n                        <label class=\"form-label\">渠道</label>\n                        <select class=\"form-select\" id=\"scenario\">\n                            <option value=\"wechat\">微信消息</option>\n                            <option value=\"email\">邮件</option>\n                            <option value=\"phone\">电话开场白</option>\n                            <option value=\"linkedin\">LinkedIn 私信</option>\n                        </select>\n                    </div>\n                    <div class=\"mb-3\">\n                        <label class=\"form-label\">目标行业</label>\n                        <input class=\"form-control\" id=\"industry\" placeholder=\"如：金融科技、SaaS、制造业\">\n                    </div>\n                    <div class=\"mb-3\">\n                        <label class=\"form-label\">我方产品/服务</label>\n                        <input class=\"form-control\" id=\"product\" placeholder=\"如：AI 销售 CRM\">\n                    </div>\n                    <div class=\"mb-3\">\n                        <label class=\"form-label\">语气风格</label>\n                        <select class=\"form-select\" id=\"tone\">\n                            <option>专业友好</option><option>亲切轻松</option>\n                            <option>直接有力</option><option>顾问式</option>\n                        </select>\n                    </div>\n                    <div class=\"mb-3\">\n                        <label class=\"form-label\">补充要求（可选）</label>\n                        <textarea class=\"form-control\" id=\"custom\" rows=\"3\" placeholder=\"如：客户是 CTO，重点讲技术集成能力\"></textarea>\n                    </div>\n                    <button class=\"btn btn-primary w-100\" id=\"btn-go\"><i class=\"bi bi-magic\"></i> 生成触达内容</button>\n                </div>\n            </div>\n        </div>\n        <div class=\"col-lg-7\">\n            <div class=\"card\">\n                <div class=\"card-header d-flex justify-content-between align-items-center\">\n                    <span><i class=\"bi bi-file-text\"></i> 生成结果 <span class=\"source-tag\" id=\"r-source\"></span></span>\n                    <button class=\"btn btn-sm btn-outline-primary\" id=\"btn-copy\"><i class=\"bi bi-clipboard\"></i> 复制</button>\n                </div>\n                <div class=\"card-body\">\n                    <pre id=\"r-content\" style=\"white-space:pre-wrap; font-family: inherit; min-height:300px; padding:15px; background:#f8f9fb; border-radius:6px;\">还没生成，先填左侧表单 →</pre>\n                    <div class=\"tips-box mt-3 small\">\n                        <strong>💡 发送建议</strong>\n                        <ul class=\"mb-0 mt-1 ps-3\" id=\"tip-list\">\n                            <li>微信：工作日上午 10-11 点、下午 3-4 点</li>\n                            <li>邮件：周二/周三 上午发送，回复率最高</li>\n                            <li>首次触达 24 小时内不重复打扰</li>\n                        </ul>\n                    </div>\n                </div>\n            </div>\n        </div>\n    </div>\n</div>\n\n<script>\ndocument.getElementById('btn-go').onclick = async () => {\n    const body = {\n        scenario: document.getElementById('scenario').value,\n        industry: document.getElementById('industry').value,\n        product: document.getElementById('product').value,\n        tone: document.getElementById('tone').value,\n        custom: document.getElementById('custom').value,\n    };\n    const btn = document.getElementById('btn-go');\n    btn.disabled = true;\n    btn.innerHTML = '<span class=\"loading-spinner\"></span> 生成中…';\n    try {\n        const r = await fetch('/api/outreach', {method: 'POST', headers: {'Content-Type': 'application/json'}, body: JSON.stringify(body)}).then(r => r.json());\n        document.getElementById('r-content').textContent = r.content;\n        const tag = document.getElementById('r-source');\n        tag.className = 'source-tag ' + r.source;\n        tag.textContent = r.source === 'real' ? '真实 AI' : 'Mock';\n    } catch (e) { alert('失败：' + e); }\n    btn.disabled = false;\n    btn.innerHTML = '<i class=\"bi bi-magic\"></i> 生成触达内容';\n};\n\ndocument.getElementById('btn-copy').onclick = () => {\n    const t = document.getElementById('r-content').textContent;\n    navigator.clipboard.writeText(t).then(() => alert('已复制'));\n};\n</script>\n{% endblock %}\n",
  "review.html": "{% extends \"base.html\" %}\n{% block title %}销售过程复盘{% endblock %}\n{% block content %}\n<div class=\"module-header\">\n    <div class=\"container\">\n        <h2><i class=\"bi bi-clipboard-data\"></i> 销售过程复盘</h2>\n        <p class=\"mb-0 opacity-75\">丢一段对话记录进来，AI 帮你拆意向度、错失点、改进项</p>\n    </div>\n</div>\n<div class=\"container\">\n    <div class=\"row g-4\">\n        <div class=\"col-lg-5\">\n            <div class=\"card\">\n                <div class=\"card-body\">\n                    <ul class=\"nav nav-tabs mb-3\">\n                        <li class=\"nav-item\"><a class=\"nav-link active\" data-bs-toggle=\"tab\" href=\"#tab-paste\">粘贴文本</a></li>\n                        <li class=\"nav-item\"><a class=\"nav-link\" data-bs-toggle=\"tab\" href=\"#tab-file\">从素材库</a></li>\n                    </ul>\n                    <div class=\"tab-content\">\n                        <div class=\"tab-pane active\" id=\"tab-paste\">\n                            <textarea class=\"form-control\" id=\"transcript\" rows=\"10\" placeholder=\"粘贴销售电话/微信/会议记录...\"></textarea>\n                        </div>\n                        <div class=\"tab-pane\" id=\"tab-file\">\n                            <p class=\"small text-muted\">从素材库中选择一份\"客户对话\"类文档：</p>\n                            <div id=\"doc-list-review\">加载中…</div>\n                        </div>\n                    </div>\n                    <button class=\"btn btn-primary w-100 mt-3\" id=\"btn-go\"><i class=\"bi bi-graph-up-arrow\"></i> 开始复盘</button>\n                </div>\n            </div>\n        </div>\n        <div class=\"col-lg-7\">\n            <div id=\"result\" class=\"d-none\">\n                <div class=\"card result-card mb-3\">\n                    <div class=\"card-body\">\n                        <div class=\"d-flex justify-content-between align-items-center mb-3\">\n                            <h5 class=\"mb-0\">📊 复盘结果 <span class=\"source-tag\" id=\"r-source\"></span></h5>\n                            <div>\n                                意向度：<span class=\"badge bg-success\" id=\"r-intent\"></span>\n                                成交概率：<span class=\"badge bg-primary\" id=\"r-prob\"></span>\n                            </div>\n                        </div>\n\n                        <div class=\"row g-3\">\n                            <div class=\"col-md-6\">\n                                <h6>😩 挖到的痛点</h6>\n                                <ul id=\"r-pains\" class=\"small\"></ul>\n                            </div>\n                            <div class=\"col-md-6\">\n                                <h6>🚧 客户异议</h6>\n                                <ul id=\"r-obj\" class=\"small\"></ul>\n                            </div>\n                            <div class=\"col-md-6\">\n                                <h6>➡️ 下一步动作</h6>\n                                <ul id=\"r-next\" class=\"small\"></ul>\n                            </div>\n                            <div class=\"col-md-6\">\n                                <h6>❌ 错失机会</h6>\n                                <ul id=\"r-missed\" class=\"small\"></ul>\n                            </div>\n                        </div>\n\n                        <h6 class=\"mt-3\">💡 改进建议</h6>\n                        <div class=\"alert alert-info\" id=\"r-imp\"></div>\n\n                        <h6>🔑 关键节点</h6>\n                        <div id=\"r-key\" class=\"small\"></div>\n                    </div>\n                </div>\n            </div>\n            <div id=\"empty\" class=\"text-center text-muted py-5\">\n                <div style=\"font-size:4rem;\">📊</div>\n                <p>粘贴对话记录，AI 会给你一份复盘报告</p>\n            </div>\n        </div>\n    </div>\n</div>\n\n<script>\nlet selectedDocId = null;\n\nasync function loadReviewDocs() {\n    const r = await fetch('/api/library/list?category=' + encodeURIComponent('客户对话')).then(r => r.json());\n    const box = document.getElementById('doc-list-review');\n    if (!r.docs.length) {\n        box.innerHTML = '<p class=\"small text-muted\">素材库中没有\"客户对话\"类文档，先到 <a href=\"/library\">素材库</a> 上传</p>';\n        return;\n    }\n    box.innerHTML = r.docs.map(d => `\n        <div class=\"form-check\">\n            <input class=\"form-check-input\" type=\"radio\" name=\"doc\" id=\"d${d.id}\" value=\"${d.id}\">\n            <label class=\"form-check-label\" for=\"d${d.id}\"><i class=\"bi bi-file-text\"></i> ${d.filename}</label>\n        </div>`).join('');\n    box.querySelectorAll('input').forEach(el => el.onchange = e => selectedDocId = e.target.value);\n}\nloadReviewDocs();\n\ndocument.getElementById('btn-go').onclick = async () => {\n    const activeTab = document.querySelector('.tab-pane.active').id;\n    const body = {};\n    if (activeTab === 'tab-paste') {\n        body.transcript = document.getElementById('transcript').value.trim();\n        if (!body.transcript) { alert('请粘贴对话记录'); return; }\n    } else {\n        if (!selectedDocId) { alert('请选择一份文档'); return; }\n        body.doc_id = selectedDocId;\n    }\n    const btn = document.getElementById('btn-go');\n    btn.disabled = true; btn.innerHTML = '<span class=\"loading-spinner\"></span> AI 分析中…';\n    try {\n        const r = await fetch('/api/review', {method: 'POST', headers: {'Content-Type': 'application/json'}, body: JSON.stringify(body)}).then(r => r.json());\n        if (!r.success) { alert(r.error || '失败'); btn.disabled = false; btn.innerHTML = '<i class=\"bi bi-graph-up-arrow\"></i> 开始复盘'; return; }\n        document.getElementById('empty').classList.add('d-none');\n        document.getElementById('result').classList.remove('d-none');\n        const d = r.data || {};\n        const tag = document.getElementById('r-source');\n        tag.className = 'source-tag ' + r.source;\n        tag.textContent = r.source === 'real' ? '真实 AI' : 'Mock';\n        document.getElementById('r-intent').textContent = safeText(d.intent) || '-';\n        document.getElementById('r-prob').textContent = safeText(d.win_prob) || '-';\n        document.getElementById('r-pains').innerHTML = (d.pain_points || []).map(x => `<li>${safeText(x)}</li>`).join('') || '<li class=\"text-muted\">-</li>';\n        document.getElementById('r-obj').innerHTML = (d.objections || []).map(x => `<li>${safeText(x)}</li>`).join('') || '<li class=\"text-muted\">-</li>';\n        document.getElementById('r-next').innerHTML = (d.next_steps || []).map(x => `<li>${safeText(x)}</li>`).join('') || '<li class=\"text-muted\">-</li>';\n        document.getElementById('r-missed').innerHTML = (d.missed || []).map(x => `<li>${safeText(x)}</li>`).join('') || '<li class=\"text-muted\">-</li>';\n        document.getElementById('r-imp').innerHTML = (d.improvements || []).map(x => `• ${safeText(x)}`).join('<br>') || '-';\n        document.getElementById('r-key').innerHTML = (d.key_moments || []).map(x => `<div class=\"border-start border-primary ps-2 mb-2\">${safeText(x)}</div>`).join('') || '<span class=\"text-muted\">-</span>';\n    } catch (e) { alert('失败：' + e); }\n    btn.disabled = false; btn.innerHTML = '<i class=\"bi bi-graph-up-arrow\"></i> 开始复盘';\n};\n</script>\n{% endblock %}\n"
}
